#!/usr/bin/env node
/**
 * Vendor the eks-agent-platform CRD schemas that `platform.yaml` is validated
 * against, and verify the vendored copies against upstream at the pinned ref.
 *
 *   node scripts/sync-crd-schemas.mjs                 # re-vendor at the pinned ref
 *   node scripts/sync-crd-schemas.mjs --ref=<sha>     # re-vendor and move the pin
 *   node scripts/sync-crd-schemas.mjs --check         # the blocking CI gate
 *   node scripts/sync-crd-schemas.mjs --freshness     # is the pin behind upstream?
 *
 * The CRDs are generated by controller-gen in nanohype/eks-agent-platform under
 * `operators/config/crd/bases/`. `platform.yaml` is applied against those exact
 * schemas, so the validator needs them — but resolving them over the network at
 * gate time would make every verdict depend on whatever upstream happens to be
 * that minute, and the tempting failure handler (skip when unreachable) is the
 * exact shape of bug the gate exists to catch. So the copies live here under
 * `schemas/crd/`, and validation is a pure function of the commit under test.
 *
 * That leaves two ways for the copies to become a lie, and `--check` closes
 * both:
 *
 *   1. Tampering. Someone edits a vendored schema — widens an enum, drops a
 *      `required` entry — and the gate happily validates against the weakened
 *      copy, because the gate's only notion of the schema IS that copy.
 *      `schemas/crd/source.json` records a SHA-256 per file;
 *      `scripts/validate-platform-manifests.mjs` verifies every digest before
 *      it reads a single schema, and `--check` here re-verifies them.
 *
 *   2. A stale or hand-moved pin. Someone bumps `upstream.ref` without
 *      re-vendoring, or re-vendors without moving the pin. The digests still
 *      agree with each other while describing a commit whose schemas are
 *      different. `--check` reads each file from upstream AT THE PINNED REF and
 *      requires the bytes to be identical, so the pin and its contents cannot
 *      diverge.
 *
 * Pin fidelity is the whole of the blocking gate, deliberately. Whether the pin
 * is also the newest thing upstream has is a different question with a
 * different answer every day, and answering it here would make a required check
 * flip red because someone pushed to another repository — a verdict about a
 * commit under test must not depend on a commit that is not. `--freshness` asks
 * that question separately and runs on a schedule, never in pull-request CI.
 *
 * Both halves of `--check` fail loudly. An unreadable manifest, a missing
 * vendored file, an unreachable upstream, a checkout sitting on the wrong
 * commit, or a fetched file that is not a CRD all exit non-zero. No path
 * through this script reports success without having compared something.
 *
 * Upstream resolves two ways, both deterministic:
 *   - `$EKS_AGENT_PLATFORM_DIR` — a checkout. Under `--check` its HEAD must
 *     equal the pinned ref; CI checks that SHA out, and a local working tree
 *     sitting on some other commit is an error rather than a silent
 *     substitution.
 *   - otherwise — raw.githubusercontent.com at the pinned ref.
 *
 * Re-vendor when the operator's API types change: run with the new `--ref`,
 * review the schema diff, and ship it with whatever `platform.yaml` change it
 * implies.
 */
import { execFile } from "node:child_process";
import { createHash } from "node:crypto";
import { readdir, readFile, writeFile } from "node:fs/promises";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";
import { promisify } from "node:util";

const SCRIPT_DIR = dirname(fileURLToPath(import.meta.url));
const ROOT = join(SCRIPT_DIR, "..");
const SCHEMA_DIR = join(ROOT, "schemas", "crd");
const SOURCE_PATH = join(SCHEMA_DIR, "source.json");
const CHECKOUT = process.env.EKS_AGENT_PLATFORM_DIR;
const CHECK = process.argv.includes("--check");
const FRESHNESS = process.argv.includes("--freshness");
const REF_ARG = process.argv.find((a) => a.startsWith("--ref="))?.slice("--ref=".length);

const exec = promisify(execFile);
const out = (line) => process.stdout.write(`${line}\n`);
const digest = (buf) => createHash("sha256").update(buf).digest("hex");
const isSha = (value) => typeof value === "string" && /^[0-9a-f]{40}$/.test(value);

function die(message, remedy) {
  process.stderr.write(`\n  ✗ ${message}\n${remedy ? `    ${remedy}\n` : ""}\n`);
  process.exit(1);
}

/**
 * Read the pin manifest. Every rule here exists because breaking it makes the
 * gate's verdict mean less than it appears to.
 */
async function readSourceManifest() {
  let manifest;
  try {
    manifest = JSON.parse(await readFile(SOURCE_PATH, "utf8"));
  } catch (err) {
    die(
      `cannot read schemas/crd/source.json (${err.message})`,
      "The vendored schemas and their source manifest travel together — restore both.",
    );
  }
  const { upstream, files } = manifest;
  if (!upstream?.repository || !upstream?.path) {
    die("schemas/crd/source.json is missing `upstream.repository` or `upstream.path`");
  }
  if (!isSha(upstream.ref)) {
    die(
      "schemas/crd/source.json `upstream.ref` must be a full 40-character commit SHA, got " +
        JSON.stringify(upstream.ref),
      "A branch name would make the gate's verdict depend on when it ran.",
    );
  }
  if (!Array.isArray(files) || files.length === 0) {
    die("schemas/crd/source.json declares no schema files");
  }
  for (const entry of files) {
    if (!entry?.file) die("schemas/crd/source.json has a `files` entry with no `file`");
    if (!/^[0-9a-f]{64}$/.test(entry.sha256 ?? "")) {
      die(`schemas/crd/source.json entry ${entry.file} carries no valid sha256 digest`);
    }
  }
  return manifest;
}

/**
 * Every `.yaml` under schemas/crd/ must be declared. An undeclared schema file
 * is un-digested and un-compared — exactly the blind spot the manifest exists
 * to remove.
 */
async function assertNoUndeclaredSchemas(manifest) {
  const declared = new Set(manifest.files.map((f) => f.file));
  const present = (await readdir(SCHEMA_DIR)).filter((f) => f.endsWith(".yaml"));
  const undeclared = present.filter((f) => !declared.has(f));
  if (undeclared.length > 0) {
    die(
      `schemas/crd/ holds files not declared in source.json: ${undeclared.join(", ")}`,
      "Add them to `files` with digests, or delete them — an undeclared schema is never verified.",
    );
  }
}

/** Resolve an upstream reader for `ref`, failing loudly if it cannot be reached. */
async function upstreamReader(manifest, ref) {
  const { repository, path } = manifest.upstream;

  if (CHECKOUT) {
    let head;
    try {
      const { stdout } = await exec("git", ["-C", CHECKOUT, "rev-parse", "HEAD"]);
      head = stdout.trim();
    } catch (err) {
      die(
        `$EKS_AGENT_PLATFORM_DIR=${CHECKOUT} is not a readable git checkout (${err.message})`,
        `Point it at a checkout of ${repository}, or unset it to read from GitHub instead.`,
      );
    }
    if (CHECK && head !== ref) {
      die(
        `$EKS_AGENT_PLATFORM_DIR is at ${head}, but schemas/crd/source.json pins ${ref}`,
        "--check compares against the pinned commit. Check that SHA out, or unset the variable.",
      );
    }
    return {
      origin: `${CHECKOUT} @ ${head}`,
      head,
      async read(file) {
        const from = join(CHECKOUT, path, file);
        try {
          return await readFile(from);
        } catch (err) {
          die(
            `cannot read ${from} (${err.message})`,
            `Is ${CHECKOUT} a checkout of ${repository}?`,
          );
        }
      },
    };
  }

  return {
    origin: `${repository}@${ref} (raw.githubusercontent.com)`,
    head: ref,
    async read(file) {
      return await fetchAtRef(repository, path, ref, file);
    },
  };
}

/** Read one schema from raw.githubusercontent.com at `ref`. Never degrades into a skip. */
async function fetchAtRef(repository, path, ref, file) {
  const url = `https://raw.githubusercontent.com/${repository}/${ref}/${path}/${file}`;
  let response;
  try {
    response = await fetch(url);
  } catch (err) {
    die(
      `cannot fetch ${url} (${err.message})`,
      "The upstream comparison is the point of this check — it does not degrade into a skip.",
    );
  }
  if (!response.ok) {
    die(
      `cannot fetch ${url}: HTTP ${response.status} ${response.statusText}`,
      "A ref that no longer resolves is a broken pin, not a passing check.",
    );
  }
  return Buffer.from(await response.arrayBuffer());
}

/**
 * Report whether the pin is behind upstream's default branch.
 *
 * Deliberately not part of `--check`: the answer changes when someone pushes to
 * eks-agent-platform, so wiring it into pull-request CI would turn an unrelated
 * upstream commit into a red required check on every open branch here. It runs
 * on a schedule instead (`.github/workflows/crd-schema-freshness.yml`), where a
 * red run is a notification that the operator API moved, not a merge blocker.
 *
 * Reads both sides at a ref rather than from a working tree, so a checkout on
 * any commit answers correctly as long as the pinned commit is reachable.
 */
async function reportFreshness(manifest) {
  const { repository, path, ref } = manifest.upstream;
  const behind = [];
  let tip;

  if (CHECKOUT) {
    try {
      await exec("git", ["-C", CHECKOUT, "cat-file", "-e", `${ref}^{commit}`]);
    } catch {
      die(
        `${ref.slice(0, 12)} is not present in $EKS_AGENT_PLATFORM_DIR=${CHECKOUT}`,
        "Check the repository out with full history (fetch-depth: 0) so the pinned commit is reachable.",
      );
    }
    const { stdout } = await exec("git", ["-C", CHECKOUT, "rev-parse", "HEAD"]);
    tip = stdout.trim();
    for (const { file } of manifest.files) {
      const [atPin, atTip] = await Promise.all([
        gitShow(CHECKOUT, ref, `${path}/${file}`),
        gitShow(CHECKOUT, "HEAD", `${path}/${file}`),
      ]);
      if (atPin === null) {
        die(
          `${path}/${file} does not exist at ${repository}@${ref.slice(0, 12)}`,
          "The pin predates this CRD, or the file was renamed — re-vendor and repin.",
        );
      }
      if (atTip === null) {
        behind.push(`${file} — removed or renamed upstream since the pin`);
      } else if (!atPin.equals(atTip)) {
        behind.push(`${file} — changed upstream between the pin and ${tip.slice(0, 12)}`);
      }
    }
  } else {
    tip = "HEAD";
    for (const { file } of manifest.files) {
      const [atPin, atTip] = await Promise.all([
        fetchAtRef(repository, path, ref, file),
        fetchAtRef(repository, path, "HEAD", file),
      ]);
      if (!atPin.equals(atTip)) {
        behind.push(`${file} — changed upstream since the pin`);
      }
    }
  }

  if (behind.length === 0) {
    out(
      `✓ the pin ${ref.slice(0, 12)} is current with ${repository}@${tip === "HEAD" ? "HEAD" : tip.slice(0, 12)}`,
    );
    return;
  }

  process.stderr.write(
    `\n  ✗ the pin ${ref.slice(0, 12)} is behind ${repository}@` +
      `${tip === "HEAD" ? "HEAD" : tip.slice(0, 12)}:\n` +
      `${behind.map((b) => `      ${b}`).join("\n")}\n` +
      "\n    Nothing is broken — the vendored copies still match the commit they claim.\n" +
      "    Adopt the newer operator API when convenient: `npm run schemas:sync -- --ref=<sha>`,\n" +
      "    review the schema diff, and ship it with whatever platform.yaml change it implies.\n\n",
  );
  process.exit(1);
}

/** `git show <ref>:<path>` as a Buffer, or null when the path is absent at that ref. */
async function gitShow(dir, ref, path) {
  try {
    const { stdout } = await exec("git", ["-C", dir, "show", `${ref}:${path}`], {
      encoding: "buffer",
      maxBuffer: 64 * 1024 * 1024,
    });
    return stdout;
  } catch {
    return null;
  }
}

async function main() {
  const modes = [CHECK, FRESHNESS, REF_ARG !== undefined].filter(Boolean).length;
  if (modes > 1) die("--check, --freshness and --ref are mutually exclusive");
  if (REF_ARG !== undefined && !isSha(REF_ARG)) {
    die(`--ref must be a full 40-character commit SHA, got ${JSON.stringify(REF_ARG)}`);
  }

  const manifest = await readSourceManifest();
  await assertNoUndeclaredSchemas(manifest);

  if (FRESHNESS) {
    await reportFreshness(manifest);
    return;
  }

  const ref = REF_ARG ?? manifest.upstream.ref;
  const source = await upstreamReader(manifest, ref);

  const tampered = [];
  const drifted = [];
  const files = [];

  for (const entry of manifest.files) {
    const upstream = await source.read(entry.file);
    if (!upstream.toString("utf8").includes("kind: CustomResourceDefinition")) {
      die(`${entry.file} from ${source.origin} is not a CustomResourceDefinition — refusing it`);
    }
    const localPath = join(SCHEMA_DIR, entry.file);

    if (CHECK) {
      let local;
      try {
        local = await readFile(localPath);
      } catch (err) {
        die(
          `vendored schema schemas/crd/${entry.file} is missing (${err.message})`,
          "Restore it with `npm run schemas:sync`.",
        );
      }
      if (digest(local) !== entry.sha256) {
        tampered.push(
          `${entry.file} — source.json records ${entry.sha256}, on disk ${digest(local)}`,
        );
      }
      if (!local.equals(upstream)) {
        drifted.push(entry.file);
      }
    } else {
      await writeFile(localPath, upstream);
      out(`  ↻ schemas/crd/${entry.file}`);
    }

    files.push({ file: entry.file, sha256: digest(upstream) });
  }

  if (CHECK) {
    if (tampered.length > 0 || drifted.length > 0) {
      if (tampered.length > 0) {
        process.stderr.write(
          "\n  ✗ vendored CRD schemas do not match their recorded digests — they were edited " +
            `in place:\n${tampered.map((t) => `      ${t}`).join("\n")}\n`,
        );
      }
      if (drifted.length > 0) {
        process.stderr.write(
          `\n  ✗ vendored CRD schemas differ from ${source.origin}:\n` +
            `${drifted.map((d) => `      schemas/crd/${d}`).join("\n")}\n`,
        );
      }
      process.stderr.write(
        "\n    Fixes belong upstream in nanohype/eks-agent-platform. To adopt a newer operator\n" +
          "    API here, run `npm run schemas:sync -- --ref=<sha>` and review the schema diff.\n" +
          "    Never hand-edit a file under schemas/crd/.\n\n",
      );
      process.exit(1);
    }
    out(
      `✓ ${manifest.files.length} vendored CRD schemas match their recorded digests and are ` +
        `byte-identical to ${source.origin}`,
    );
    return;
  }

  const pinned = { ...manifest, upstream: { ...manifest.upstream, ref: source.head }, files };
  await writeFile(SOURCE_PATH, `${JSON.stringify(pinned, null, 2)}\n`);
  out(`✓ vendored from ${source.origin}; pin and digests rewritten`);
}

main().catch((err) => {
  process.stderr.write(`\n  ✗ sync-crd-schemas failed: ${err.stack ?? err.message}\n\n`);
  process.exit(1);
});
